55	const BASE_PREMIUM: Record<string, number> = {
56	  sword: 100,
57	  amulet: 60,
58	  staff: 80,
59	  potion: 40,
60	  rune: 25,
61	};
62	
63	const COMPONENT_PRICE = 25;
64	const BLOCK_SIZE = 3;
65	const BLOCK_PRICE = 60;
66	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
67	
68	const INITIAL_ASSESSMENT_RATE = 0.1;
69	const CURSE_SURCHARGE_RATE = 0.5;
70	const HIGH_ENCHANTMENT_RATE = 0.3;
71	const HIGH_ENCHANTMENT_THRESHOLD = 5;
72	const LOYALTY_DISCOUNT_RATE = 0.2;
73	const LOYALTY_YEARS_THRESHOLD = 2;
74	const FOLLOWUP_DISCOUNT_RATE = 0.15;
75	const PROCESSING_FEE = 5;
76	const FLOAT_PRECISION_DIGITS = 6;
77	
78	const itemOwnBase = (item: Item): number => {
79	  return COMPONENT_TYPES.has(item.type)
80	    ? COMPONENT_PRICE
81	    : BASE_PREMIUM[item.type];
82	};
83	
84	const itemSurcharge = (item: Item): number => {
85	  const own = itemOwnBase(item);
86	  const curse = item.cursed ? CURSE_SURCHARGE_RATE * own : 0;
87	  const highEnchantment =
88	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
89	      ? HIGH_ENCHANTMENT_RATE * own
90	      : 0;
91	  return curse + highEnchantment;
92	};
93	
94	const componentBase = (count: number): number => {
95	  return count === BLOCK_SIZE ? BLOCK_PRICE : count * COMPONENT_PRICE;
96	};
97	
98	const countByType = (items: Item[]): Map<string, number> => {
99	  const counts = new Map<string, number>();
100	  for (const item of items) {
101	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
102	  }
103	  return counts;
104	};
105	
106	const itemBaseTotal = (items: Item[]): number => {
107	  let total = 0;
108	  for (const [type, count] of countByType(items)) {
109	    total += COMPONENT_TYPES.has(type)
110	      ? componentBase(count)
111	      : BASE_PREMIUM[type] * count;
112	  }
113	  return total;
114	};
115	
116	const quotePremium = (
117	  step: QuoteStep,
118	  customer: Customer,
119	  isFollowUp: boolean,
120	): number => {
121	  const policyBase = itemBaseTotal(step.items);
122	  const surcharges = step.items.reduce(
123	    (sum, item) => sum + itemSurcharge(item),
124	    0,
125	  );
126	  const initialAssessment = INITIAL_ASSESSMENT_RATE * policyBase;
127	  const loyaltyDiscount =
128	    customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD
129	      ? LOYALTY_DISCOUNT_RATE * policyBase
130	      : 0;
131	  const followUpDiscount = isFollowUp ? FOLLOWUP_DISCOUNT_RATE * policyBase : 0;
132	  const premium =
133	    policyBase +
134	    surcharges +
135	    initialAssessment -
136	    loyaltyDiscount -
137	    followUpDiscount +
138	    PROCESSING_FEE;
139	  return Math.ceil(Number(premium.toFixed(FLOAT_PRECISION_DIGITS)));
140	};
141	
142	export const runScenario = (scenario: Scenario): ScenarioResult => {
143	  let quotesSeen = 0;
144	  const results = scenario.steps.map((step) => {
145	    const isFollowUp = quotesSeen >= 1;
146	    quotesSeen += 1;
147	    return { premium: quotePremium(step as QuoteStep, scenario.customer, isFollowUp) };
148	  });
149	  return { results };
150	};
