export const runScenario = (scenario: Scenario): ScenarioResult => {
  let quotesSeen = 0;
  const results = scenario.steps.map((step) => {
    const isFollowUp = quotesSeen >= 1;
    quotesSeen += 1;
    return { premium: quotePremium(step as QuoteStep, scenario.customer, isFollowUp) };
  });
  return { results };
};

