export const runScenario = (scenario: Scenario): ScenarioResult => {
  const results = scenario.steps.map((step, index) => {
    const isFollowUp = index > 0;
    return {
      premium: quotePremium(step as QuoteStep, scenario.customer, isFollowUp),
    };
  });
  return { results };
};
